const setTheme = (_designConfiguration: ActionPageDesignConfiguration) => {
  const colorMap = new Map<string, string>([
    [
      "--brand-primary-foreground",
      // default slate-700
      "oklch(37.2% 0.044 257.287)",
    ],
    ["--brand-primary", "oklch(100% 0 0)"],
